Here’s the same responder written in JavaScript (Node / browser‑compatible):

```javascript
function responder(message) {
    // Simple text‑based responder
    const lowered = message.toLowerCase();

    if (lowered.includes('hello') || lowered.includes('hi')) {
        return "Hey there! How can I help you today?";
    }
    if (lowered.includes('thanks') || lowered.includes('thank you')) {
        return "You’re welcome! Anything else you need?";
    }
    if (lowered.includes('code')) {
        return "Sure thing! Let me know what language or problem you’re tackling.";
    }
    // Default fallback
    return "I’m here if you want to chat or need assistance.";
}

// Example usage (Node.js)
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

function chat() {
    readline.question('You: ', input => {
        if (input.toLowerCase() === 'exit' || input.toLowerCase() === 'quit') {
            console.log('Responder: Bye!');
            readline.close();
        } else {
            console.log('Responder:', responder(input));
            chat();
        }
    });
}

chat();
```

